        let mut count = 0;
        let mut power = 1;
        while power <= n {
            count += 1;
            power <<= 1;
        }
        return count as i64;
    }

    // Precompute all possible popcount depths for numbers up to n
    // Since k is small (<= 5), we can use BFS to find numbers with exact depth k
    let mut visited = std::collections::HashSet::new();
    let mut queue = std::vec::Vec::new();

    // Start with all numbers from 1 to n
    for i in 1..=n {
        queue.push((i, 0));
        visited.insert(i);
    }

    // BFS to find numbers with exact depth k
    let mut count = 0;
    while let Some((value, depth)) = queue.pop() {
        if depth == k {
            count += 1;
        } else if depth < k {
            let next = popcount(value);
            if !visited.contains(&next) && next <= n {
                visited.insert(next);
                queue.push((next, depth + 1));
            }
        }
    }

    count
}

